ClassLoader loader = String.class.getClassLoader();
ClassLoader app = Thread.currentThread().getContextClassLoader();
assert loader == null && app != null;

CompletableFuture<Integer> base = CompletableFuture.completedFuture(2);
int mapped = base.thenApply(v -> v * 2).join();
int chained = base.thenCompose(v -> CompletableFuture.completedFuture(v * 3)).join();
assert mapped == 4 && chained == 6;

